import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { SeedService } from '../../data/seed.service';

@Component({
  selector: 'app-contacts',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './contacts.component.html',
  styleUrl: './contacts.component.css',
})
export class ContactsComponent {
  today = new Date('2026-07-10');
  filter = signal('');

  filtered = computed(() => {
    const q = this.filter().trim().toLowerCase();
    if (!q) return this.seed.contacts();
    return this.seed.contacts().filter((c) => c.name.toLowerCase().includes(q));
  });

  totalContacts = computed(() => this.seed.contacts().length);
  championCount = computed(() => this.seed.contacts().filter((c) => c.isChampion).length);
  staleCount = computed(() =>
    this.seed.contacts().filter((c) => this.daysSince(c.lastTouch) > 30).length,
  );

  daysSince(iso: string): number {
    const then = new Date(iso).getTime();
    return Math.round((this.today.getTime() - then) / 86400000);
  }

  strengthBadge(strength: string): string {
    switch (strength) {
      case 'strong': return 'badge-success';
      case 'developing': return 'badge-warning';
      case 'new': return 'badge-info';
      default: return 'badge-neutral';
    }
  }

  onFilter(value: string): void {
    this.filter.set(value);
  }

  constructor(public seed: SeedService) {}
}
